def solve(deps: dict[str, list[str]]) -> list[list[str]]:
    nodes = set()
    for task, prereqs in deps.items():
        nodes.add(task)
        for p in prereqs:
            nodes.add(p)

    in_degree = {n: 0 for n in nodes}
    adj = {n: [] for n in nodes}

    for task, prereqs in deps.items():
        for p in set(prereqs):
            adj[p].append(task)
            in_degree[task] += 1

    res = []
    while True:
        current_layer = [n for n in nodes if in_degree[n] == 0]
        if not current_layer:
            break
        current_layer.sort()
        res.append(current_layer)
        for u in current_layer:
            in_degree[u] = -1
            for v in adj[u]:
                in_degree[v] -= 1

    if sum(len(layer) for layer in res) != len(nodes):
        return []
    return res
