from collections import OrderedDict

def solve(capacity: int, ops: list[str]) -> list[int]:
    res = []
    if capacity <= 0:
        for op in ops:
            parts = op.split()
            if parts[0] == 'get':
                res.append(-1)
        return res
    cache = OrderedDict()
    for op in ops:
        parts = op.split()
        if parts[0] == 'get':
            key = int(parts[1])
            if key not in cache:
                res.append(-1)
            else:
                cache.move_to_end(key)
                res.append(cache[key])
        elif parts[0] == 'put':
            key = int(parts[1])
            value = int(parts[2])
            if key in cache:
                cache[key] = value
                cache.move_to_end(key)
            else:
                if len(cache) == capacity:
                    cache.popitem(last=False)
                cache[key] = value
    return res
