import bisect

def solve(nums: list[int], k: int) -> list[float]:
    if not nums or k <= 0 or len(nums) < k:
        return []
    window = sorted(nums[:k])
    res = []
    mid = k // 2
    if k % 2 == 1:
        res.append(float(window[mid]))
    else:
        res.append((window[mid - 1] + window[mid]) / 2.0)
    for i in range(k, len(nums)):
        left_val = nums[i - k]
        del_idx = bisect.bisect_left(window, left_val)
        window.pop(del_idx)
        bisect.insort(window, nums[i])
        if k % 2 == 1:
            res.append(float(window[mid]))
        else:
            res.append((window[mid - 1] + window[mid]) / 2.0)
    return res
